    if (vec_ok) {
        for (uint32_t b = lane; b < xq_blocks; b += 32u) {
            dev_dot_q4_K_q8_K_block_vec(gr + b, xqb + b, &gate);
            dev_dot_q4_K_q8_K_block_vec(ur + b, xqb + b, &up);
